"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["56074"],{12035(e){e.exports=JSON.parse('{"tag":{"label":".Net SDK","permalink":"/tags/net-sdk","allTagsPath":"/tags","count":21,"items":[{"id":"develop/dotnet/index","title":".Net SDK developer guide","description":"Use the Temporal .NET SDK to develop Temporal Applications, connect to the Temporal Service, test Workflows and Activities, handle failures, send messages, and more.","permalink":"/develop/dotnet/"},{"id":"develop/dotnet/asynchronous-activity","title":"Asynchronous Activity completion - .NET SDK","description":"Asynchronously complete an Activity in Temporal. Follow simple steps to allow an Activity Function to return without the Activity Execution completing.","permalink":"/develop/dotnet/asynchronous-activity"},{"id":"develop/dotnet/benign-exceptions","title":"Benign exceptions - .NET SDK","description":"Mark expected or non-severe Activity errors as benign to reduce noise in logs, metrics, and OpenTelemetry traces.","permalink":"/develop/dotnet/benign-exceptions"},{"id":"develop/dotnet/child-workflows","title":"Child Workflows - .NET SDK","description":"Start a Child Workflow Execution and set a Parent Close Policy using Temporal .NET SDK. Discover methods like ExecuteChildWorkflowAsync and manage Workflow behaviors.","permalink":"/develop/dotnet/child-workflows"},{"id":"develop/dotnet/continue-as-new","title":"Continue-As-New - .NET SDK","description":"Use Temporal\'s Continue-As-New in .NET to manage large Event Histories by atomically creating new Workflow Executions with the same Workflow Id and fresh parameters.","permalink":"/develop/dotnet/continue-as-new"},{"id":"develop/dotnet/converters-and-encryption","title":"Converters and encryption - .NET SDK","description":"Use a custom Payload Codec and Converter in the .NET SDK to modify Temporal Data Conversion behavior, including examples for encryption and camel case conversion.","permalink":"/develop/dotnet/converters-and-encryption"},{"id":"develop/dotnet/core-application","title":"Core application - .NET SDK","description":"Develop a basic Workflow and Activity Definition using the Temporal .NET SDK, run a Worker Process, and set up Dynamic Workflows and Activities.","permalink":"/develop/dotnet/core-application"},{"id":"develop/dotnet/debugging","title":"Debugging - .NET SDK","description":"Debug Workflows in development and production environments using Temporal .NET SDK. Use logging, debugger, Web UI, CLI, replay, tracing, and more for efficient troubleshooting.","permalink":"/develop/dotnet/debugging"},{"id":"develop/dotnet/durable-timers","title":"Durable Timers - .NET SDK","description":"Set a Durable Timer using the Temporal .NET SDK. Pause Workflow execution for days or months. Timers are persisted and highly resource-efficient using Workflow.DelayAsync.","permalink":"/develop/dotnet/durable-timers"},{"id":"develop/dotnet/enriching-ui","title":"Enriching the user interface - .NET SDK","description":"Add contextual information to Workflows and events in the Temporal UI using the .NET SDK.","permalink":"/develop/dotnet/enriching-ui"},{"id":"develop/dotnet/failure-detection","title":"Failure detection - .NET SDK","description":"Optimize Workflow Execution with Temporal .Net SDK - Set Timeouts, Retry Policies, and manage Activity Heartbeats efficiently.","permalink":"/develop/dotnet/failure-detection"},{"id":"develop/dotnet/cancellation","title":"Interrupt a Workflow - .NET SDK","description":"Interrupt Workflow Execution in .NET using the Temporal SDK. Cancel for graceful stops; terminate for forceful stops. Handle Cancellation in Workflow and Activities efficiently.","permalink":"/develop/dotnet/cancellation"},{"id":"develop/dotnet/observability","title":"Observability - .NET SDK","description":"Explore Temporal SDK observability features for Metrics, Tracing, Logging, and Visibility. Track Workflow Executions, set up Prometheus endpoints, customize metrics, configure tracing, and more.","permalink":"/develop/dotnet/observability"},{"id":"develop/dotnet/schedules","title":"Schedules - .NET SDK","description":"Manage and optimize Scheduled Workflows using the Temporal .NET SDK; Schedule, Create, Backfill, Update, Delete, Describe, List, Pause, Trigger, and use Start Delay options.","permalink":"/develop/dotnet/schedules"},{"id":"develop/dotnet/set-up-your-local-dotnet","title":"Set up your local with the .NET SDK","description":"Configure your local development environment to get started developing with Temporal","permalink":"/develop/dotnet/set-up-your-local-dotnet"},{"id":"develop/dotnet/standalone-activities","title":"Standalone Activities - .NET SDK","description":"Execute Activities independently without a Workflow using the Temporal .NET SDK.","permalink":"/develop/dotnet/standalone-activities"},{"id":"develop/dotnet/temporal-client","title":"Temporal Client - .NET SDK","description":"Create a Temporal Client, connect to Temporal Cloud, start a Workflow, and get Workflow results using the Temporal .NET SDK with detailed steps and code examples.","permalink":"/develop/dotnet/temporal-client"},{"id":"develop/dotnet/nexus","title":"Temporal Nexus - .NET SDK feature guide","description":"Use Temporal Nexus within the .NET SDK to connect Durable Executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/dotnet/nexus"},{"id":"develop/dotnet/testing-suite","title":"Testing - .NET SDK","description":"The .NET test-suite guide covers Workflow and integration testing for Temporal. It includes end-to-end, integration, and unit testing, emphasizing the use of the test server to optimize test execution.","permalink":"/develop/dotnet/testing-suite"},{"id":"develop/dotnet/versioning","title":"Versioning - .NET SDK","description":"Use the .NET SDK Patching API to safely deploy new code versions, handle deprecated patches, and manage Workflow activities using Temporal for long-running tasks.","permalink":"/develop/dotnet/versioning"},{"id":"develop/dotnet/message-passing","title":"Workflow message passing - .NET SDK","description":"Develop with Queries, Signals, and Updates with the Temporal .NET SDK.","permalink":"/develop/dotnet/message-passing"}],"unlisted":false}}')}}]);